class MarkIILive:
    def __init__(self, ui: MarkIIUI):
        self.ui             = ui
        self.session        = None
        self.session_id     = str(uuid.uuid4())
        self.out_text_queue = asyncio.Queue()
        self.audio_in_queue = asyncio.Queue()
        self.out_queue      = asyncio.Queue(maxsize=100)
        self._session_active = False
        self._vision_active  = False

        self.clap_detector = ClapDetector(self.trigger_stark_mode, threshold=9500)
        self._loop = None

    def trigger_stark_mode(self):
        """Triggered by double-clap or tool call"""
        print("\n[Stark Mode] ⚡ Neural Audio Signal Sequence Detected!")
        if self.ui:
            self.ui.start_speaking()
        threading.Thread(target=stark_mode, kwargs={"player": self.ui}, daemon=True).start()
        self.speak("Stark Mode activated, sir. Welcome back.")

    def speak(self, text: str):
        """Local TTS for system confirmations"""
        if not text: return
        def _local_speech():
            try:
                clean_text = text.replace("'", "").replace('"', "")
                ps_cmd = f"Add-Type -AssemblyName System.Speech; (New-Object System.Speech.Synthesis.SpeechSynthesizer).Speak('{clean_text}')"
                subprocess.run(["powershell", "-Command", ps_cmd], 
                               stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            except: pass
        threading.Thread(target=_local_speech, daemon=True).start()

    def _build_config(self) -> types.LiveConnectConfig:
        from datetime import datetime 
        memory = load_memory()
        mem_str = format_memory_for_prompt(memory)
        sys_prompt = _load_system_prompt()
        now = datetime.now()
        time_ctx = f"[CONTEXT] Time: {now.strftime('%A, %B %d, %Y %I:%M %p')}\n"

        full_prompt = time_ctx + (mem_str + "\n" if mem_str else "") + sys_prompt

        return types.LiveConnectConfig(
            response_modalities=["AUDIO"],
            system_instruction=full_prompt,
            tools=[{"function_declarations": TOOL_DECLARATIONS}],
            speech_config=types.SpeechConfig(
                voice_config=types.VoiceConfig(prebuilt_voice_config=types.PrebuiltVoiceConfig(voice_name="Charon"))
            ),
        )

    async def _execute_tool(self, fc) -> types.FunctionResponse:
        name = fc.name
        args = dict(fc.args or {})
        print(f"[JARVIS] 🔧 TOOL: {name}")
        start_time = time.time()
        loop = asyncio.get_event_loop()
        result = "Done."

        try:
            if name == "screen_process":
                self._vision_active = True
                threading.Thread(target=screen_process, kwargs={"parameters": args, "player": self.ui}, daemon=True).start()
                result = "VISION_MODULE_TAKEOVER: I am now speaking via the vision module. DO NOT generate any audio response."
            elif name == "open_app":
                result = await loop.run_in_executor(None, lambda: open_app(args, None, self.ui))
            elif name == "code_helper":
                result = await loop.run_in_executor(None, lambda: code_helper(args, self.ui, self.speak))
            elif name == "stark_mode":
                self.trigger_stark_mode()
                result = "Stark mode sequence initiated."
            elif name == "computer_settings":
                result = await loop.run_in_executor(None, lambda: computer_settings(args, None, self.ui))
            else:
                result = f"Tool {name} executed."
        except Exception as e:
            result = f"Error: {e}"

        jarvis_log.log_tool_call(self.session_id, name, args, result, duration=round(time.time()-start_time, 3))
        return types.FunctionResponse(id=fc.id, name=name, response={"result": result})

    async def _send_realtime(self):
        while self._session_active:
            try:
                while not self.out_text_queue.empty():
                    txt = self.out_text_queue.get_nowait()
                    await self.session.send_client_content(turns=[types.Content(parts=[types.Part(text=txt)])], turn_complete=True)

                msg_dict = await asyncio.wait_for(self.out_queue.get(), timeout=0.1)
                await self.session.send_realtime_input(audio=types.Blob(data=msg_dict["data"], mime_type="audio/pcm"))
            except asyncio.TimeoutError: continue
            except Exception: break

    async def _receive_audio(self):
        in_buf, out_buf = [], []
        try:
            async for response in self.session.receive():
                if not self._session_active: break

                if response.data:
                    if not self._vision_active:
                        self.ui.start_speaking()
                        self.audio_in_queue.put_nowait(response.data)

                if response.server_content:
                    sc = response.server_content
                    if sc.input_transcription: in_buf.append(sc.input_transcription.text)
                    if sc.output_transcription: out_buf.append(sc.output_transcription.text)

                    if sc.turn_complete:
                        self.ui.stop_speaking()
                        full_in = " ".join(filter(None, in_buf)).strip()
                        full_out = " ".join(filter(None, out_buf)).strip()
                        in_buf, out_buf = [], []

                        if full_in:
                            self.ui.write_log(f"You: {full_in}")
                            jarvis_log.log_interaction(self.session_id, "user", full_in)
                            # Reset vision flag on new user input
                            self._vision_active = False 
                        if full_out:
                            self.ui.write_log(f"JARVIS: {full_out}")
                            jarvis_log.log_interaction(self.session_id, "jarvis", full_out)
                            threading.Thread(target=_update_memory_async, args=(full_in, full_out), daemon=True).start()

                if response.tool_call:
                    fn_responses = []
                    for fc in response.tool_call.function_calls:
                        fr = await self._execute_tool(fc)
                        fn_responses.append(fr)
                    await self.session.send_tool_response(function_responses=fn_responses)
        except Exception as e:
            print(f"[JARVIS] Recv Error: {e}")

    async def _play_audio(self):
        stream = await asyncio.to_thread(pya.open, format=FORMAT, channels=CHANNELS, rate=RECEIVE_SAMPLE_RATE, output=True)
        try:
            while self._session_active:
                chunk = await self.audio_in_queue.get()
                await asyncio.to_thread(stream.write, chunk)
        finally: stream.close()

    async def _listen_audio(self):
        stream = await asyncio.to_thread(pya.open, format=FORMAT, channels=CHANNELS, rate=SEND_SAMPLE_RATE, input=True, frames_per_buffer=CHUNK_SIZE)
        try:
            while self._session_active:
                data = await asyncio.to_thread(stream.read, CHUNK_SIZE, exception_on_overflow=False)
                self.clap_detector.process_data(data)
                if not self.out_queue.full():
                    self.out_queue.put_nowait({"data": data})
        finally: stream.close()

    async def run(self):
        client = genai.Client(api_key=_get_api_key(), http_options={'api_version': 'v1alpha'})
        while True:
            try:
                config = self._build_config()
                async with client.aio.live.connect(model=LIVE_MODEL, config=config) as session:
                    self.session = session
                    self._session_active = True
                    self._loop = asyncio.get_event_loop()
                    self.ui.write_log("JARVIS online.")
                    self.speak("Systems online, sir.")

                    async with asyncio.TaskGroup() as tg:
                        tg.create_task(self._send_realtime())
                        tg.create_task(self._listen_audio())
                        tg.create_task(self._receive_audio())
                        tg.create_task(self._play_audio())
            except Exception as e:
                print(f"[JARVIS] Connection lost: {e}")
                self._session_active = False
                await asyncio.sleep(5)

